---@class LBattleViewHudGroup
local LBattleViewHudGroup = classX("LBattleViewHudGroup", nil)

local LBattleViewHud = require("LApp.gameplay.videobattle.view.obj.LBattleViewHud")

---@param viewUnit LBattleViewUnit
function LBattleViewHudGroup:ctor(uiRect, hudCacheMgr, viewUnit)
    self._uiRect = uiRect

    ---@type LBattleViewUnit
    self._unit = viewUnit

    ---@type LBattleHudCacheMgr
    self._hudCacheMgr = hudCacheMgr

    ---@type table<number, LBattleViewHud[]>
    self._hudList = {}

    self._maxGroup = 0

    self._hudGroupSort = {}

    self._idx = 0

    self:InitColIndex()
end



function LBattleViewHudGroup:InitColIndex()
    local gridIndex = self._unit:GetIndex() or 0
    local side = self._unit:GetTeamIdx()
    if side == BattleTeamSide.teamA then
        if gridIndex > 6 then
            self._colIndex = 1
        elseif gridIndex > 3 then
            self._colIndex = 2
        else
            self._colIndex = 3
        end
    else
        if gridIndex > 6 then
            self._colIndex = 3
        elseif gridIndex > 3 then
            self._colIndex = 2
        else
            self._colIndex = 1
        end
    end
end

---@param player LBattleSkillPlayer
function LBattleViewHudGroup:CreateHud(startTime, hudParam, player)
    if self._isDisposed then return end
    local heroRace = hudParam.heroRace
    local hudDataList = self:SplitHurtDataList(hudParam.changeType, hudParam.hurt, hudParam.playNum)
    for k,v in ipairs(hudDataList) do
        v.heroRace = heroRace
        local hud = LBattleViewHud:new()
        hud:AttachCacheMgr(self._hudCacheMgr)
        hud:AttachUnit(self._unit)
        hud:AttacheUi(self._uiRect)
        hud:SetPlayer(player)
        hud:Initialize(self._colIndex, self._idx, {v}, hudParam)
        hud:SetStartTime(startTime + (v:GetDelay() or 0))
        self:AddHud(hud)
        self._idx = self._idx + 1
    end
end

---@return LFightHudData[]
function LBattleViewHudGroup:SplitHurtDataList(changeType,hurt,playNum)
    if not hurt then
        return {self:NewHudData(changeType,0,0,0)}
    end

    if #playNum < 1 then
        return {self:NewHudData(changeType,hurt,0,0)}
    end

    local floatHurtY = 30
    local hurtDataList = {}
    local totalHurt = hurt

    local timeDelay = 0
    local oneHurt = nil
    for i, v in ipairs(playNum) do
        oneHurt =  math.floor(v[2] * hurt)
        totalHurt = totalHurt - oneHurt
        table.insert(hurtDataList,self:NewHudData(changeType,oneHurt,timeDelay,floatHurtY))
        timeDelay = v[1]
    end
    if totalHurt > 0 then
        table.insert(hurtDataList,self:NewHudData(changeType,totalHurt,timeDelay,floatHurtY))
    end
    return hurtDataList
end

--hud数据
function LBattleViewHudGroup:NewHudData(changeType,hurt,delay,floatHurtY)
    local data = require("LApp.gameplay.videobattle.data.LFightHudData"):new(changeType,hurt,delay,floatHurtY)
    return data
end

function LBattleViewHudGroup:AddHud(hud)
    local group = hud:GetGroup()
    local vList = self._hudList[group]
    if not vList then
        vList = {}
        self._hudList[group] = vList
    end
    table.insert(vList,hud)

    self._hudGroupSort[group] = true
    if group > self._maxGroup then
        self._maxGroup = group
    end
end

-----------------------------------------------------------------
function LBattleViewHudGroup:OnUpdate(time)
    if self._isDisposed then return end
    local hudList = self._hudList
    for k=0, self._maxGroup do
        self:OnUpdateList(k, hudList[k], time)
    end
end

-----------------------------------------------------------------
local function sortHudFunc(a, b)
    local timeA = a:GetStartTime()
    local timeB = b:GetStartTime()
    if timeA ~= timeB then
        return timeA < timeB
    end
    return a:GetIdx() < b:GetIdx()
end

---@param hudList LBattleViewHud[]
function LBattleViewHudGroup:OnUpdateList(group, hudList, time)
    if not hudList or #hudList == 0 then return end
    if self._hudGroupSort[group] then
        self._hudGroupSort[group] = nil
        if(#hudList > 1) then
            table.sort(hudList, sortHudFunc)
        end
    end
    local delIndex = {}
    local lastPlayIndex = 0
    local oldPlaying = false
    for k,v in ipairs(hudList) do
        oldPlaying = v:IsPlaying()
        if not v:OnUpdate(time) then
            table.insert(delIndex,k)
        else
            if not oldPlaying and v:IsPlaying() then
                lastPlayIndex = k
            end
        end
    end

    local delLen = #delIndex
    for k=delLen,1,-1 do
        local hud = table.remove(hudList,delIndex[k])
        hud:Dispose()
    end

    if group == LFightConst.HUD_GROUP_HURT or group == LFightConst.HUD_GROUP_BUFF then
        --lastPlayIndex = lastPlayIndex - delLen
        --if lastPlayIndex > 1 then
        --	--伤害数字 和buff 名字， 新出现的会把旧的往上顶一段距离
        --	local upY = 20
        --	for k=lastPlayIndex-1,1,-1  do
        --		local hud = hudList[k]
        --		hud:UpHudNodePos(upY)
        --		upY = upY + 20
        --	end
        --end
        local playingList = {}
        for k,v in ipairs(hudList) do
            if v:IsPlaying() then
                table.insert(playingList,v)
            end
        end
        local cnt = #playingList
        for k,v in ipairs(playingList) do
            v:SetGroupOffset(cnt - k)
        end
    end
end

------------------------------------------------------------------
function LBattleViewHudGroup:ClearHud()
    if self._hudList ~= nil then
        for k, vList in pairs(self._hudList) do
            for _, v in ipairs(vList) do
                v:Dispose()
            end
            self._hudList[k] = nil
        end
        self._hudList = nil
    end
end

function LBattleViewHudGroup:IsDisposed()
    return self._isDisposed
end

function LBattleViewHudGroup:Dispose()
    if self._isDisposed then return end
    self:ClearHud()
    table.dispose(self)
    self._isDisposed = true
end
